class MainActivity : AppCompatActivity() {

    companion object {
        private const val TAG = "HybridApp"
        private const val WEB_APP_URL = "file:///android_asset/index.html" // or your remote URL
        private const val NOTIFICATION_CHANNEL_ID = "hybrid_app_channel"
        private const val NOTIFICATION_CHANNEL_NAME = "Hybrid App Notifications"
    }

    private lateinit var webView: WebView
    private var cameraPermissionLauncher: ActivityResultLauncher<String>? = null
    private var notificationPermissionLauncher: ActivityResultLauncher<String>? = null
    private var takePictureLauncher: ActivityResultLauncher<Void?>? = null
    private var capturedBitmap: Bitmap? = null
    private var pendingWebPermissionRequest: PermissionRequest? = null
    private var fileUploadCallback: ValueCallback<Array<Uri>>? = null

    private var fileChooserLauncher: ActivityResultLauncher<String>? = null

    @SuppressLint("SetJavaScriptEnabled")
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        createNotificationChannel()
        setupActivityResultLaunchers()

        webView = findViewById(R.id.webView)
        configureWebView()
        webView.loadUrl(WEB_APP_URL)
    }

    private fun setupActivityResultLaunchers() {
        cameraPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            if (isGranted) {
                pendingWebPermissionRequest?.grant(pendingWebPermissionRequest?.resources)
                webView.evaluateJavascript(
                    "javascript:window.onNativeCameraPermissionResult(true)", null
                )
            } else {
                pendingWebPermissionRequest?.deny()
                webView.evaluateJavascript(
                    "javascript:window.onNativeCameraPermissionResult(false)", null
                )
            }
            pendingWebPermissionRequest = null
        }

        notificationPermissionLauncher = registerForActivityResult(
            ActivityResultContracts.RequestPermission()
        ) { isGranted ->
            webView.evaluateJavascript(
                "javascript:window.onNativeNotificationPermissionResult($isGranted)", null
            )
        }

        takePictureLauncher = registerForActivityResult(
            ActivityResultContracts.TakePicturePreview()
        ) { bitmap ->
            if (bitmap != null) {
                capturedBitmap = bitmap
                val base64 = bitmapToBase64(bitmap)
                val escapedBase64 = base64.replace("'", "\\'")
                webView.evaluateJavascript(
                    "javascript:window.onNativeCameraCapture('data:image/jpeg;base64,$escapedBase64')",
                    null
                )
            } else {
                webView.evaluateJavascript(
                    "javascript:window.onNativeCameraCapture(null)", null
                )
            }
        }

        fileChooserLauncher = registerForActivityResult(
            ActivityResultContracts.GetContent()
        ) { uri ->
            fileUploadCallback?.onReceiveValue(if (uri != null) arrayOf(uri) else arrayOf())
            fileUploadCallback = null
        }
    }

    @SuppressLint("SetJavaScriptEnabled")
    private fun configureWebView() {
        webView.settings.apply {
            javaScriptEnabled = true
            domStorageEnabled = true
            databaseEnabled = true
            allowFileAccess = true
            allowContentAccess = true
            mediaPlaybackRequiresUserGesture = false
            mixedContentMode = WebSettings.MIXED_CONTENT_COMPATIBILITY_MODE
            cacheMode = WebSettings.LOAD_DEFAULT
            setSupportZoom(true)
            builtInZoomControls = true
            displayZoomControls = false
            useWideViewPort = true
            loadWithOverviewMode = true

            if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                safeBrowsingEnabled = true
            }
        }

        // Add JavaScript interface bridge
        webView.addJavascriptInterface(NativeBridge(this), "NativeBridge")

        webView.webViewClient = object : WebViewClient() {
            override fun shouldOverrideUrlLoading(
                view: WebView?,
                request: WebResourceRequest?
            ): Boolean {
                // Keep navigation within the WebView
                return false
            }

            override fun onPageFinished(view: WebView?, url: String?) {
                super.onPageFinished(view, url)
                Log.d(TAG, "Page loaded: $url")
                // Inject bridge availability notification
                webView.evaluateJavascript(
                    """
                    javascript:
                    if (window.onNativeBridgeReady) {
                        window.onNativeBridgeReady();
                    }
                    window.dispatchEvent(new CustomEvent('nativeBridgeReady'));
                    """.trimIndent(), null
                )
            }
        }

        webView.webChromeClient = object : WebChromeClient() {
            override fun onPermissionRequest(request: PermissionRequest?) {
                request?.let { req ->
                    val resources = req.resources
                    if (resources.contains(PermissionRequest.RESOURCE_VIDEO_CAPTURE)) {
                        pendingWebPermissionRequest = req
                        if (ContextCompat.checkSelfPermission(
                                this@MainActivity,
                                Manifest.permission.CAMERA
                            ) == PackageManager.PERMISSION_GRANTED
                        ) {
                            req.grant(resources)
                            pendingWebPermissionRequest = null
                        } else {
                            cameraPermissionLauncher?.launch(Manifest.permission.CAMERA)
                        }
                    } else {
                        req.grant(resources)
                    }
                }
            }

            override fun onConsoleMessage(consoleMessage: ConsoleMessage?): Boolean {
                consoleMessage?.let {
                    Log.d(TAG, "WebView Console: ${it.message()} [${it.sourceId()}:${it.lineNumber()}]")
                }
                return true
            }

            override fun onShowFileChooser(
                webView: WebView?,
                filePathCallback: ValueCallback<Array<Uri>>?,
                fileChooserParams: FileChooserParams?
            ): Boolean {
                fileUploadCallback?.onReceiveValue(null)
                fileUploadCallback = filePathCallback
                fileChooserLauncher?.launch("*/*")
                return true
            }
        }

        // Enable debugging in debug builds
        WebView.setWebContentsDebuggingEnabled(BuildConfig.DEBUG)
    }

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                NOTIFICATION_CHANNEL_NAME,
                NotificationManager.IMPORTANCE_DEFAULT
            ).apply {
                description = "Notifications from Hybrid App"
            }
            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    fun requestCameraPermissionAndCapture() {
        if (ContextCompat.checkSelfPermission(
                this, Manifest.permission.CAMERA
            ) == PackageManager.PERMISSION_GRANTED
        ) {
            takePictureLauncher?.launch(null)
        } else {
            cameraPermissionLauncher?.launch(Manifest.permission.CAMERA)
        }
    }

    fun requestNotificationPermission() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
            if (ContextCompat.checkSelfPermission(
                    this, Manifest.permission.POST_NOTIFICATIONS
                ) != PackageManager.PERMISSION_GRANTED
            ) {
                notificationPermissionLauncher?.launch(Manifest.permission.POST_NOTIFICATIONS)
                return
            }
        }
        runOnUiThread {
            webView.evaluateJavascript(
                "javascript:window.onNativeNotificationPermissionResult(true)", null
            )
        }
    }

    fun showLocalNotification(title: String, message: String, notificationId: Int) {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU &&
            ContextCompat.checkSelfPermission(
                this, Manifest.permission.POST_NOTIFICATIONS
            ) != PackageManager.PERMISSION_GRANTED
        ) {
            Log.w(TAG, "Notification permission not granted")
            return
        }

        val notification = NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setSmallIcon(android.R.drawable.ic_dialog_info)
            .setContentTitle(title)
            .setContentText(message)
            .setPriority(NotificationCompat.PRIORITY_DEFAULT)
            .setAutoCancel(true)
            .build()

        NotificationManagerCompat.from(this).notify(notificationId, notification)
    }

    fun saveCapturedImageToGallery(): Boolean {
        val bitmap = capturedBitmap ?: return false
        return try {
            val timestamp = SimpleDateFormat("yyyyMMdd_HHmmss", Locale.US).format(Date())
            val filename = "HybridApp_$timestamp.jpg"

            val contentValues = ContentValues().apply {
                put(MediaStore.MediaColumns.DISPLAY_NAME, filename)
                put(MediaStore.MediaColumns.MIME_TYPE, "image/jpeg")
                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.Q) {
                    put(MediaStore.MediaColumns.RELATIVE_PATH, Environment.DIRECTORY_PICTURES)
                }
            }

            val uri = contentResolver.insert(
                MediaStore.Images.Media.EXTERNAL_CONTENT_URI, contentValues
            )

            uri?.let {
                contentResolver.openOutputStream(it)?.use { stream ->
                    bitmap.compress(Bitmap.CompressFormat.JPEG, 90, stream)
                }
                true
            } ?: false
        } catch (e: Exception) {
            Log.e(TAG, "Error saving image: ${e.message}")
            false
        }
    }

    private fun bitmapToBase64(bitmap: Bitmap): String {
        val stream = ByteArrayOutputStream()
        bitmap.compress(Bitmap.CompressFormat.JPEG, 85, stream)
        val byteArray = stream.toByteArray()
        return Base64.encodeToString(byteArray, Base64.NO_WRAP)
    }

    override fun onBackPressed() {
        if (webView.canGoBack()) {
            webView.goBack()
        } else {
            super.onBackPressed()
        }
    }

    override fun onDestroy() {
        webView.destroy()
        super.onDestroy()
    }

    // ============================================================
    // JavaScript Interface Bridge
    // ============================================================
    inner class NativeBridge(private val context: Context) {

        // --- Camera Functions ---

        @JavascriptInterface
        fun requestCameraAccess() {
            runOnUiThread {
                (context as? MainActivity)?.requestCameraPermissionAndCapture()
            }
        }

        @JavascriptInterface
        fun hasCameraPermission(): Boolean {
            return ContextCompat.checkSelfPermission(
                context, Manifest.permission.CAMERA
            ) == PackageManager.PERMISSION_GRANTED
        }

        @JavascriptInterface
        fun savePhotoToGallery(): Boolean {
            return (context as? MainActivity)?.saveCapturedImageToGallery() ?: false
        }

        // --- Local Storage Functions ---

        @JavascriptInterface
        fun setItem(key: String, value: String) {
            val prefs = context.getSharedPreferences("hybrid_app_storage", Context.MODE_PRIVATE)
            prefs.edit().putString(key, value).apply()
        }

        @JavascriptInterface
        fun getItem(key: String): String? {
            val prefs = context.getSharedPreferences("hybrid_app_storage", Context.MODE_PRIVATE)
            return prefs.getString(key, null)
        }

        @JavascriptInterface
        fun removeItem(key: String) {
            val prefs = context.getSharedPreferences("hybrid_app_storage", Context.MODE_PRIVATE)
            prefs.edit().remove(key).apply()
        }

        @JavascriptInterface
        fun clearStorage() {
            val prefs = context.getSharedPreferences("hybrid_app_storage", Context.MODE_PRIVATE)
            prefs.edit().clear().apply()
        }

        @JavascriptInterface
        fun getAllKeys(): String {
            val prefs = context.getSharedPreferences("hybrid_app_storage", Context.MODE_PRIVATE)
            val keys = prefs.all.keys.toList()
            return JSONObject().apply {
                put("keys", org.json.JSONArray(keys))
            }.toString()
        }

        @JavascriptInterface
        fun setSecureItem(key: String, value: String) {
            val prefs = context.getSharedPreferences("hybrid_app_secure_storage", Context.MODE_PRIVATE)
            // In production, use EncryptedSharedPreferences from AndroidX Security
            val encoded = Base64.encodeToString(value.toByteArray(), Base64.NO_WRAP)
            prefs.edit().putString(key, encoded).apply()
        }

        @JavascriptInterface
        fun getSecureItem(key: String): String? {
            val prefs = context.getSharedPreferences("hybrid_app_secure_storage", Context.MODE_PRIVATE)
            val encoded = prefs.getString(key, null) ?: return null
            return String(Base64.decode(encoded, Base64.NO_WRAP))
        }

        // --- Push Notification Functions ---

        @JavascriptInterface
        fun requestNotificationPermission() {
            runOnUiThread {
                (context as? MainActivity)?.requestNotificationPermission()
            }
        }

        @JavascriptInterface
        fun hasNotificationPermission(): Boolean {
            return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.TIRAMISU) {
                ContextCompat.checkSelfPermission(
                    context, Manifest.permission.POST_NOTIFICATIONS
                ) == PackageManager.PERMISSION_GRANTED
            } else {
                NotificationManagerCompat.from(context).areNotificationsEnabled()
            }
        }

        @JavascriptInterface
        fun showNotification(title: String, message: String) {
            val notificationId = System.currentTimeMillis().toInt()
            (context as? MainActivity)?.showLocalNotification(title, message, notificationId)
        }

        @JavascriptInterface
        fun showNotificationWithId(title: String, message: String, id: Int) {
            (context as? MainActivity)?.showLocalNotification(title, message, id)
        }

        @JavascriptInterface
        fun cancelNotification(id: Int) {
            NotificationManagerCompat.from(context).cancel(id)
        }

        @JavascriptInterface
        fun cancelAllNotifications() {
            NotificationManagerCompat.from(context).cancelAll()
        }

        // --- Device Info Functions ---

        @JavascriptInterface
        fun getDeviceInfo(): String {
            return JSONObject().apply {
                put("manufacturer", Build.MANUFACTURER)
                put("model", Build.MODEL)
                put("osVersion", Build.VERSION.RELEASE)
                put("sdkVersion", Build.VERSION.SDK_INT)
                put("appVersion", try {
                    context.packageManager.getPackageInfo(context.packageName, 0).versionName
                } catch (e: Exception) { "unknown" })
            }.toString()
        }

        @JavascriptInterface
        fun getPlatform(): String {
            return "android"
        }

        // --- Utility Functions ---

        @JavascriptInterface
        fun showToast(message: String) {
            runOnUiThread {
                Toast.makeText(context, message, Toast.LENGTH_SHORT).show()
            }
        }

        @JavascriptInterface
        fun showLongToast(message: String) {
            runOnUiThread {
                Toast.makeText(context, message, Toast.LENGTH_LONG).show()
            }
        }

        @JavascriptInterface
        fun log(message: String) {
            Log.d(TAG, "JS Bridge: $message")
        }

        @JavascriptInterface
        fun copyToClipboard(text: String) {
            runOnUiThread {
                val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE)
                        as android.content.ClipboardManager
                val clip = android.content.ClipData.newPlainText("Copied Text", text)
                clipboard.setPrimaryClip(clip)
            }
        }

        @JavascriptInterface
        fun getClipboardText(): String {
            val clipboard = context.getSystemService(Context.CLIPBOARD_SERVICE)
                    as android.content.ClipboardManager
            return clipboard.primaryClip?.getItemAt(0)?.text?.toString() ?: ""
        }

        @JavascriptInterface
        fun vibrate(milliseconds: Long) {
            runOnUiThread {
                val vibrator = if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.S) {
                    val vibratorManager = context.getSystemService(Context.VIBRATOR_MANAGER_SERVICE)
                            as android.os.VibratorManager
                    vibratorManager.defaultVibrator
                } else {
                    @Suppress("DEPRECATION")
                    context.getSystemService(Context.VIBRATOR_SERVICE) as android.os.Vibrator
                }

                if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
                    vibrator.vibrate(
                        android.os.VibrationEffect.createOneShot(
                            milliseconds,
                            android.os.VibrationEffect.DEFAULT_AMPLITUDE
                        )
                    )
                } else {
                    @Suppress("DEPRECATION")
                    vibrator.vibrate(milliseconds)
                }
            }
        }

        @JavascriptInterface
        fun shareText(title: String, text: String) {
            runOnUiThread {
                val intent = android.content.Intent(android.content.Intent.ACTION_SEND).apply {
                    type = "text/plain"
                    putExtra(android.content.Intent.EXTRA_TEXT, text)
                }
                context.startActivity(android.content.Intent.createChooser(intent, title))
            }
        }
    }
